import{_ as t,o as s,c as a,ag as i}from"./chunks/framework.CvgP6Fyv.js";const b=JSON.parse('{"title":"Objets et actifs","description":"","frontmatter":{},"headers":[],"relativePath":"fr/features/objects.md","filePath":"fr/features/objects.md"}'),o={name:"fr/features/objects.md"};function r(l,e,n,u,c,d){return s(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="objets-et-actifs" tabindex="-1">Objets et actifs <a class="header-anchor" href="#objets-et-actifs" aria-label="Permalink to &quot;Objets et actifs&quot;">​</a></h1><p>Suivez les biens locatifs, vehicules, equipements et autres actifs professionnels avec une gestion complete du cycle de vie.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Le module objets est optionnel. Activez-le dans <strong>Entreprise &gt; Fonctionnalites</strong> si vous ne le voyez pas dans la navigation.</p></div><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><p>Le module objets est concu pour les entreprises qui gerent des actifs physiques -- en particulier les societes de location, les gestionnaires de biens immobiliers et les services de location d&#39;equipements. Chaque objet represente un actif que vous possedez ou gerez.</p><h2 id="types-d-objets" tabindex="-1">Types d&#39;objets <a class="header-anchor" href="#types-d-objets" aria-label="Permalink to &quot;Types d&#39;objets&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Cas d&#39;utilisation</th></tr></thead><tbody><tr><td><strong>Propriete</strong></td><td>Appartements locatifs, bureaux, locaux commerciaux</td></tr><tr><td><strong>Vehicule</strong></td><td>Voitures, camions, utilitaires, vehicules de chantier</td></tr><tr><td><strong>Machine</strong></td><td>Equipements industriels, outils, generateurs</td></tr><tr><td><strong>Autre</strong></td><td>Tout autre type d&#39;actif</td></tr></tbody></table><h2 id="statuts-des-objets" tabindex="-1">Statuts des objets <a class="header-anchor" href="#statuts-des-objets" aria-label="Permalink to &quot;Statuts des objets&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Statut</th><th>Description</th></tr></thead><tbody><tr><td><strong>Disponible</strong></td><td>Pret a etre loue ou utilise</td></tr><tr><td><strong>Loue</strong></td><td>Actuellement loue a un client</td></tr><tr><td><strong>Inactif</strong></td><td>Non disponible (maintenance, retire)</td></tr></tbody></table><h2 id="creer-un-objet" tabindex="-1">Creer un objet <a class="header-anchor" href="#creer-un-objet" aria-label="Permalink to &quot;Creer un objet&quot;">​</a></h2><ol><li>Allez dans <strong>Objets &gt; Nouvel objet</strong></li><li>Remplissez : <ul><li><strong>Nom</strong> -- Un identifiant clair (par ex., &quot;Appartement 3B&quot; ou &quot;Pelleteuse CAT 320&quot;)</li><li><strong>Type</strong> -- Propriete, Vehicule, Machine ou Autre</li><li><strong>Statut</strong> -- Disponible, Loue ou Inactif</li><li><strong>Description</strong> -- Details sur l&#39;actif</li></ul></li><li>Cliquez sur <strong>Enregistrer</strong></li></ol><h2 id="page-de-detail-de-l-objet" tabindex="-1">Page de detail de l&#39;objet <a class="header-anchor" href="#page-de-detail-de-l-objet" aria-label="Permalink to &quot;Page de detail de l&#39;objet&quot;">​</a></h2><p>La page de detail affiche :</p><ul><li>Informations sur l&#39;actif et son type</li><li>Statut actuel</li><li>Contrats lies</li><li>Historique de location</li><li>Factures associees</li></ul><h2 id="lier-les-objets-aux-contrats-et-factures" tabindex="-1">Lier les objets aux contrats et factures <a class="header-anchor" href="#lier-les-objets-aux-contrats-et-factures" aria-label="Permalink to &quot;Lier les objets aux contrats et factures&quot;">​</a></h2><p>Les objets s&#39;integrent aux autres fonctionnalites de MyCompanyDesk :</p><ul><li><strong>Contrats</strong> -- Creez un contrat de location pour un objet, en specifiant le locataire (client) et les conditions</li><li><strong>Factures</strong> -- Les factures peuvent etre marquees comme factures de location et liees aux objets</li><li><strong>Factures recurrentes</strong> -- Configurez une facturation mensuelle automatique par objet</li></ul><h2 id="filtrage" tabindex="-1">Filtrage <a class="header-anchor" href="#filtrage" aria-label="Permalink to &quot;Filtrage&quot;">​</a></h2><p>Filtrez vos objets par :</p><ul><li><strong>Type</strong> -- Propriete, Vehicule, Machine, Autre</li><li><strong>Statut</strong> -- Disponible, Loue, Inactif</li><li><strong>Recherche</strong> -- Trouvez par nom ou description</li></ul><h2 id="actions-groupees" tabindex="-1">Actions groupees <a class="header-anchor" href="#actions-groupees" aria-label="Permalink to &quot;Actions groupees&quot;">​</a></h2><ul><li><strong>Changer le statut</strong> -- Mettez a jour la disponibilite en masse</li><li><strong>Archiver</strong> -- Deplacez vers les archives</li><li><strong>Supprimer</strong> -- Supprimez des objets</li></ul><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Utilisez le filtre de statut pour voir rapidement quels actifs sont disponibles a la location</li><li>Liez chaque facture de location a son objet pour un suivi financier complet par actif</li><li>Configurez des contrats avec recurrence pour la facturation automatique des loyers</li><li>Consultez les indicateurs d&#39;objets en haut de la page pour un apercu de la disponibilite</li></ul>',24)])])}const h=t(o,[["render",r]]);export{b as __pageData,h as default};
